import { Switch as SwitchPrimitive } from "@base-ui/react/switch";
import * as stylex from "@stylexjs/stylex";
import { switchStyles } from "./switch.styles";

type Props = Omit<SwitchPrimitive.Root.Props, "style"> & {
  style?: stylex.StyleXStyles;
};

export function Switch({ style, ...props }: Props) {
  const rootProps = stylex.props(switchStyles.root, style);
  return (
    <SwitchPrimitive.Root
      {...props}
      {...rootProps}
      render={(rootProps, { checked, disabled }) => (
        <span
          {...rootProps}
          {...stylex.props(
            switchStyles.root,
            checked && switchStyles.rootChecked,
            disabled && switchStyles.rootDisabled,
            style,
          )}
        >
          <SwitchPrimitive.Thumb
            {...stylex.props(switchStyles.thumb, checked && switchStyles.thumbChecked)}
          />
        </span>
      )}
    />
  );
}

import * as stylex from "@stylexjs/stylex";
import { borderRadius, spacing, theme } from "@/lib/theme/contract.stylex";

export const switchStyles = stylex.create({
  root: {
    width: spacing.xxlarge,
    height: spacing.large,
    display: "inline-flex",
    alignItems: "center",
    padding: spacing.xxsmall,
    borderRadius: borderRadius.full,
    backgroundColor: theme.border,
    cursor: "pointer",
    transitionProperty: "background-color",
    transitionDuration: "150ms",
    ":focus-visible": {
      outlineWidth: 2,
      outlineStyle: "solid",
      outlineColor: theme.borderStrong,
    },
  },
  rootChecked: {
    backgroundColor: theme.primary,
  },
  rootDisabled: {
    cursor: "not-allowed",
    opacity: 0.35,
  },
  thumb: {
    width: spacing.large,
    height: spacing.large,
    borderRadius: borderRadius.full,
    backgroundColor: theme.primary,
    transitionProperty: "transform, background-color",
    transitionDuration: "150ms",
    transform: "translateX(0)",
  },
  thumbChecked: {
    backgroundColor: theme.surface,
    transform: `translateX(${spacing.large})`,
  },
});
